arguments.file_text:
@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        <span class="bi bi-plus-circle me-1"></span> New Shipment
    </button>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editing ? "Edit Shipment" : "Create Shipment")</div>
        <div class="card-body">
            <EditForm Model="formModel" OnValidSubmit="SaveShipment" FormName="shipmentForm">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="formModel.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="formModel.Destination" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Recipient Name</label>
                        <InputText class="form-control" @bind-Value="formModel.RecipientName" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Recipient Email</label>
                        <InputText class="form-control" @bind-Value="formModel.RecipientEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="formModel.Status">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="formModel.EstimatedDelivery" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="formModel.Notes" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success me-2">Save</button>
                    <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditShipment(s)">Edit</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteShipment(s.Id)">Delete</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private Shipment formModel = new();
    private bool showForm;
    private bool editing;
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        formModel = new Shipment { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
        editing = false;
        showForm = true;
    }

    private void EditShipment(Shipment shipment)
    {
        formModel = new Shipment
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            RecipientName = shipment.RecipientName,
            RecipientEmail = shipment.RecipientEmail,
            Status = shipment.Status,
            EstimatedDelivery = shipment.EstimatedDelivery,
            Notes = shipment.Notes
        };
        editing = true;
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (editing)
        {
            await ShipmentService.UpdateShipmentAsync(formModel);
        }
        else
        {
            await ShipmentService.CreateShipmentAsync(formModel);
        }

        showForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void CancelForm() => showForm = false;

    private async Task DeleteShipment(int id)
    {
        await ShipmentService.DeleteShipmentAsync(id);
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Customer")]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking #:</strong> <code>@shipment.TrackingNumber</code></span>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6 class="text-muted">Route</h6>
                    <p class="fs-5">@shipment.Origin → @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Estimated Delivery</h6>
                    <p class="fs-5">@shipment.EstimatedDelivery.ToString("dddd, MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Recipient</h6>
                    <p>@shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Shipped On</h6>
                    <p>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                </div>
                @if (!string.IsNullOrEmpty(shipment.Notes))
                {
                    <div class="col-12">
                        <h6 class="text-muted">Notes</h6>
                        <p>@shipment.Notes</p>
                    </div>
                }
            </div>

