            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking #:</strong> <code>@shipment.TrackingNumber</code></span>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6 class="text-muted">Route</h6>
                    <p class="fs-5">@shipment.Origin → @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Estimated Delivery</h6>
                    <p class="fs-5">@shipment.EstimatedDelivery.ToString("dddd, MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Recipient</h6>
                    <p>@shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Shipped On</h6>
                    <p>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                </div>
                @if (!string.IsNullOrEmpty(shipment.Notes))
                {
                    <div class="col-12">
                        <h6 class="text-muted">Notes</h6>
                        <p>@shipment.Notes</p>
                    </div>
                }
            </div>

            <hr />
            <h6 class="text-muted mb-3">Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool searching;

