@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Customer")]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking #:</strong> <code>@shipment.TrackingNumber</code></span>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6 class="text-muted">Route</h6>
                    <p class="fs-5">@shipment.Origin → @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Estimated Delivery</h6>
                    <p class="fs-5">@shipment.EstimatedDelivery.ToString("dddd, MMMM dd, yyyy")</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Recipient</h6>
                    <p>@shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Shipped On</h6>
                    <p>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                </div>
                @if (!string.IsNullOrEmpty(shipment.Notes))
                {
                    <div class="col-12">
                        <h6 class="text-muted">Notes</h6>
                        <p>@shipment.Notes</p>
                    </div>
                }
            </div>

            <hr />
            <h6 class="text-muted mb-3">Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool searching;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

