using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        return await db.Shipments.FindAsync(id);
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = GenerateTrackingNumber();
        shipment.CreatedAt = DateTime.UtcNow;
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var existing = await db.Shipments.FindAsync(shipment.Id)
            ?? throw new InvalidOperationException("Shipment not found");

        existing.Origin = shipment.Origin;
        existing.Destination = shipment.Destination;
        existing.Status = shipment.Status;
        existing.EstimatedDelivery = shipment.EstimatedDelivery;
        existing.RecipientName = shipment.RecipientName;
        existing.RecipientEmail = shipment.RecipientEmail;
        existing.Notes = shipment.Notes;

        await db.SaveChangesAsync();
        return existing;
    }

    public async Task DeleteShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
        }
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

