using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents()
    .AddAuthenticationStateSerialization(options =>
        options.SerializeAllClaims = true);

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<IdentityRedirectManager>();
builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();

builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = IdentityConstants.ApplicationScheme;
        options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
    })
    .AddIdentityCookies();

var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlite(connectionString));
builder.Services.AddDatabaseDeveloperPageExceptionFilter();

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = true;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })
    .AddRoles<IdentityRole>()
    .AddEntityFrameworkStores<ApplicationDbContext>()
    .AddSignInManager()
    .AddDefaultTokenProviders();

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
    app.UseMigrationsEndPoint();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

// Shipment API endpoints
var api = app.MapGroup("api/shipments").RequireAuthorization();

api.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()));

api.MapGet("/{id:int}", async (int id, IShipmentService service) =>
    await service.GetShipmentByIdAsync(id) is { } shipment
        ? Results.Ok(shipment)
        : Results.NotFound());

api.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
    await service.GetShipmentByTrackingNumberAsync(trackingNumber) is { } shipment
        ? Results.Ok(shipment)
        : Results.NotFound());

api.MapPost("/", async (Shipment shipment, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(shipment);
    return Results.Created($"api/shipments/{created.Id}", created);
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

api.MapPut("/{id:int}", async (int id, Shipment shipment, IShipmentService service) =>
{
    shipment.Id = id;
    var updated = await service.UpdateShipmentAsync(shipment);
    return Results.Ok(updated);
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

api.MapDelete("/{id:int}", async (int id, IShipmentService service) =>
{
    await service.DeleteShipmentAsync(id);
    return Results.NoContent();
}).RequireAuthorization(p => p.RequireRole("Dispatcher"));

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Seed roles and sample data
await SeedDataAsync(app);

app.Run();

static async Task SeedDataAsync(WebApplication app)
{
    using var scope = app.Services.CreateScope();
    var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
    var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();

    await db.Database.MigrateAsync();

    string[] roles = ["Dispatcher", "Customer"];
    foreach (var role in roles)
    {
        if (!await roleManager.RoleExistsAsync(role))
            await roleManager.CreateAsync(new IdentityRole(role));
    }

    // Seed a dispatcher account
    if (await userManager.FindByEmailAsync("dispatcher@shiptracker.com") is null)
    {
        var dispatcher = new ApplicationUser
        {
            UserName = "dispatcher@shiptracker.com",
            Email = "dispatcher@shiptracker.com",
            EmailConfirmed = true
        };
        await userManager.CreateAsync(dispatcher, "Dispatch1!");
        await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
    }

    // Seed a customer account
    if (await userManager.FindByEmailAsync("customer@example.com") is null)
    {
        var customer = new ApplicationUser
        {
            UserName = "customer@example.com",
            Email = "customer@example.com",
            EmailConfirmed = true
        };
        await userManager.CreateAsync(customer, "Customer1!");
        await userManager.AddToRoleAsync(customer, "Customer");
    }

    // Seed sample shipments
    if (!await db.Shipments.AnyAsync())
    {
        db.Shipments.AddRange(
            new Shipment
            {
                TrackingNumber = "SHP-20260501-100001",
                Origin = "New York, NY",
                Destination = "Los Angeles, CA",
                Status = ShipmentStatus.InTransit,
                CreatedAt = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                RecipientName = "Alice Johnson",
                RecipientEmail = "alice@example.com",
                Notes = "Fragile — handle with care"
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260501-100002",
                Origin = "Chicago, IL",
                Destination = "Miami, FL",
                Status = ShipmentStatus.OutForDelivery,
                CreatedAt = DateTime.UtcNow.AddDays(-5),
                EstimatedDelivery = DateTime.UtcNow,
                RecipientName = "Bob Smith",
                RecipientEmail = "bob@example.com"
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260501-100003",
                Origin = "Seattle, WA",
                Destination = "Denver, CO",
                Status = ShipmentStatus.Delivered,
                CreatedAt = DateTime.UtcNow.AddDays(-7),
                EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
                RecipientName = "Carol Davis",
                RecipientEmail = "carol@example.com"
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260501-100004",
                Origin = "Boston, MA",
                Destination = "Houston, TX",
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = DateTime.UtcNow.AddDays(6),
                RecipientName = "Dan Wilson",
                RecipientEmail = "dan@example.com"
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260501-100005",
                Origin = "San Francisco, CA",
                Destination = "Phoenix, AZ",
                Status = ShipmentStatus.Delayed,
                CreatedAt = DateTime.UtcNow.AddDays(-4),
                EstimatedDelivery = DateTime.UtcNow.AddDays(3),
                RecipientName = "Eve Martinez",
                RecipientEmail = "eve@example.com",
                Notes = "Weather delay at hub"
            }
        );
        await db.SaveChangesAsync();
    }
}

